Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": {
    "name": "dataset"
  },
  "transform": [
    {
      "fold": [
        "Order Lines YTD",
        "Order Lines (PY) YTD"
      ],
      "as": [
        "Measure",
        "Value"
      ]
    },
    {
      "window": [
        {
          "op": "row_number",
          "as": "row"
        }
      ],
      "groupby": [
        "Measure"
      ]
    },
    {
      "calculate": "datum.row === 12 ? datum.Value : null",
      "as": "LastValue"
    }
  ],
  "layer": [
    {
      "mark": {
        "type": "line",
        "strokeWidth": 3.5,
        "point": false
      },
      "encoding": {
        "x": {
          "field": "Calendar Month (ie Jan)",
          "type": "nominal",
          "axis": {
            "title": null,
            "grid": false,
            "labelAngle": -45
          },
          "sort": [
            "Jan",
            "Feb",
            "Mar",
            "Apr",
            "May",
            "Jun",
            "Jul",
            "Aug",
            "Sep",
            "Oct",
            "Nov",
            "Dec"
          ]
        },
        "y": {
          "field": "Value",
          "type": "quantitative",
          "axis": {
            "title": null,
            "grid": false,
            "labelColor": "#6C757D",
            "labelFontSize": 12,
            "format": ",.3s"
          },
          "scale": {
            "zero": true
          }
        },
        "color": {
          "field": "Measure",
          "type": "nominal",
          "scale": {
            "domain": [
              "Order Lines YTD",
              "Order Lines (PY) YTD"
            ],
            "range": [
              "#5B8DBE",
              "#D4A574"
            ]
          },
          "legend": null
        },
        "strokeDash": {
          "field": "Measure",
          "type": "nominal",
          "scale": {
            "domain": [
              "Order Lines YTD",
              "Order Lines (PY) YTD"
            ],
            "range": [
              [
                1,
                0
              ],
              [
                5,
                5
              ]
            ]
          },
          "legend": null
        }
      }
    },
    {
      "mark": {
        "type": "point",
        "filled": true,
        "size": 100,
        "stroke": "white",
        "strokeWidth": 2
      },
      "encoding": {
        "x": {
          "field": "Calendar Month (ie Jan)",
          "type": "nominal",
          "sort": [
            "Jan",
            "Feb",
            "Mar",
            "Apr",
            "May",
            "Jun",
            "Jul",
            "Aug",
            "Sep",
            "Oct",
            "Nov",
            "Dec"
          ]
        },
        "y": {
          "field": "LastValue",
          "type": "quantitative"
        },
        "color": {
          "field": "Measure",
          "type": "nominal",
          "scale": {
            "domain": [
              "Order Lines YTD",
              "Order Lines (PY) YTD"
            ],
            "range": [
              "#5B8DBE",
              "#D4A574"
            ]
          },
          "legend": null
        }
      }
    },
    {
      "mark": {
        "type": "text",
        "align": "left",
        "dx": 5,
        "dy": -10,
        "fontSize": 18,
        "fontWeight": 600
      },
      "encoding": {
        "x": {
          "field": "Calendar Month (ie Jan)",
          "type": "nominal",
          "sort": [
            "Jan",
            "Feb",
            "Mar",
            "Apr",
            "May",
            "Jun",
            "Jul",
            "Aug",
            "Sep",
            "Oct",
            "Nov",
            "Dec"
          ]
        },
        "y": {
          "field": "LastValue",
          "type": "quantitative"
        },
        "text": {
          "field": "LastValue",
          "type": "quantitative",
          "format": ",.3s"
        },
        "color": {
          "field": "Measure",
          "type": "nominal",
          "scale": {
            "domain": [
              "Order Lines YTD",
              "Order Lines (PY) YTD"
            ],
            "range": [
              "#5B8DBE",
              "#D4A574"
            ]
          },
          "legend": null
        }
      }
    }
  ]
}'
